import{BaseComponent as e,html as t,define as n}from"../core.min.js";export class DvConfirm extends e{initialState(){return{pending:!1}}proceed(){if(!this.state.pending){this.state.pending=!0;return}this.state.pending=!1,this.emit("confirm",{value:this.str("value")})}cancel(){this.state.pending=!1,this.emit("cancel")}template(){return this.state.pending?t`<span class="dv-confirm" role="group" aria-label="${this.str("label","Confirm action")}"><span>${this.str("message","Are you sure?")}</span><button type="button" data-on:click="proceed">${this.str("confirm-label","Confirm")}</button><button type="button" data-on:click="cancel">${this.str("cancel-label","Cancel")}</button></span>`:t`<button type="button" class="dv-confirm" data-on:click="proceed">${this.str("label","Delete")}</button>`}}n("dv-confirm",DvConfirm);
